namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateSingleItem(string name = "Widget", decimal price = 10m, int quantity = 1) =>
    [
        new OrderItem { ProductName = name, Price = price, Quantity = quantity }
    ];

    #region CreateOrder

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var items = CreateSingleItem();

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        // Arrange
        var items = CreateSingleItem();

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var items = CreateSingleItem();
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = CreateSingleItem(price: 25.50m, quantity: 3);

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalAcrossAllItems()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 5m, Quantity = 3 },
            new() { ProductName = "Doohickey", Price = 20m, Quantity = 1 }
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert — (10*2) + (5*3) + (20*1) = 55
        Assert.AreEqual(55m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        // Arrange
        var items = CreateSingleItem();

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateSingleItem();

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        // Arrange
        var created = _service.CreateOrder("cust-1", CreateSingleItem());

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithOrders_ReturnsMatchingOrders()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateSingleItem());
        _service.CreateOrder("cust-1", CreateSingleItem());
        _service.CreateOrder("cust-2", CreateSingleItem());

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoMatchingOrders_ReturnsEmptyList()
    {
        // Arrange
        _service.CreateOrder("cust-1", CreateSingleItem());

        // Act
        var orders = _service.GetOrdersByCustomer("cust-999");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyOrdersForSpecifiedCustomer()
    {
        // Arrange
        var order1 = _service.CreateOrder("cust-1", CreateSingleItem());
        _service.CreateOrder("cust-2", CreateSingleItem());

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual(order1.Id, single.Id);
    }

    #endregion
}

